// ===============================
// SAFE EXTRACTION FROM MODEL NODE
// ===============================

// 1️⃣ Get the input data
const inputData = $input.first().json;
let raw = null;

// Handle different possible n8n/AI output structures
if (inputData.output && Array.isArray(inputData.output) && inputData.output[0]?.content?.[0]?.text) {
  raw = inputData.output[0].content[0].text;
} else if (typeof inputData.output === "string") {
  raw = inputData.output;
} else if (typeof inputData.text === "string") {
  raw = inputData.text;
} else if (typeof inputData.output === "object") {
  // If it's already an object, stringify it so the cleaner can process it or skip to assignment
  raw = JSON.stringify(inputData.output);
}

if (!raw) {
  throw new Error("No model text found in input");
}

// 2️⃣ Clean JSON formatting (remove ```json blocks)
const cleanJson = raw.replace(/```json|```/gi, "").trim();

// 3️⃣ Parse the JSON safely
let obj; // Declared once here
try {
  obj = JSON.parse(cleanJson);
} catch (err) {
  throw new Error("Invalid JSON from model:\n" + cleanJson);
}

// ===============================
// BUILD FINAL OUTPUT
// ===============================
const out = {};

// --- TOP LEVEL ---
out.score = Number(obj.score) || 0;
out.priority = (obj.priority || "").toString().trim();
out.go_nogo = obj.go_nogo || "";
out.reasons = Array.isArray(obj.reasons) ? obj.reasons.join(" || ") : (obj.reasons || "");
out.summary = obj.summary || "";

// --- FIT ---
out.alignment = obj.fit?.alignment || "";
out.type = obj.fit?.type || "";
out.budget_class = obj.fit?.budget_class || "";
out.delivery_mode = obj.fit?.delivery_mode || "";
out.deadline_ok = obj.fit?.deadline_ok ?? "";

// --- DETAILS ---
const d = obj.details || {};
out.client = d.client || "";
out.type_opportunite = d.type_opportunite || "";

// --- MODE DE PASSATION MAPPING ---
const modeTxt = (d.mode_passation || "").toLowerCase();
if (modeTxt.includes("ao ouvert")) out.mode_passation = "4247d725742a05e7";
else if (modeTxt.includes("consultation")) out.mode_passation = "f374dfea602ed07e";
else if (modeTxt.includes("manifestation")) out.mode_passation = "70069e67a2e765de";
else out.mode_passation = "";

// --- COMPANY & CONTACT ---
out.nom_societe = d.nom_societe || "";
out.adresse = d.adresse || "";
out.rue = d.rue || "";
out.ville = d.ville || "";
out.etat = d.etat || "";
out.code_postal = d.code_postal || "";
out.pays = d.pays || "";
out.site_web = d.site_web || "";
out.langue = d.langue || "";
out.nom_contact = d.nom_contact || "";
out.titre_contact = d.titre_contact || "";
out.email = d.email || "";
out.poste = d.poste || "";
out.mobile = d.mobile || "";
out.vendeur = d.vendeur || "";
out.equipe_commerciale = d.equipe_commerciale || "";
out.secteur_activite = d.secteur_activite || "";
out.taille_entreprise = d.taille_entreprise || "";
out.nb_annees_experience = d.nb_annees_experience || "";
out.description = d.description || "";

// --- NUMERIC ---
out.budget = Number(d.budget) || 0;
out.Caution = Number(d.Caution) || 0;

// --- DATE FORMAT FOR ODOO ---
const rawDate = d.date_limite_soumission;
if (rawDate) {
  const date = new Date(rawDate);
  if (!isNaN(date)) {
    const yyyy = date.getFullYear();
    const mm = String(date.getMonth() + 1).padStart(2, "0");
    const dd = String(date.getDate()).padStart(2, "0");
    const hh = String(date.getHours()).padStart(2, "0");
    const mi = String(date.getMinutes()).padStart(2, "0");
    const ss = String(date.getSeconds()).padStart(2, "0");
    out.date_limite_soumission = `${yyyy}-${mm}-${dd} ${hh}:${mi}:${ss}`;
  } else {
    out.date_limite_soumission = null;
  }
} else {
  out.date_limite_soumission = null;
}

// --- STRATEGIC / UPLOAD / RISKS ---
function arrayToBullet(arr) {
  if (!Array.isArray(arr)) return arr || "";
  return arr.map((s) => `• ${s}`).join("\n");
}

out.strategic_value = arrayToBullet(obj.strategic_value);
out.upload_step = arrayToBullet(obj.upload_step);
out.risks = arrayToBullet(obj.risks);

// --- NEXT ACTIONS ---
const na = (Array.isArray(obj.next_actions) ? obj.next_actions[0] : obj.next_actions) || {};
out.owner = na.owner || "";
out.action = na.action || "";
out.sla_hours = Number(na.sla_hours) || 0;

// --- STEPS ---
if (Array.isArray(na.steps)) {
  out.steps_summary = na.steps
    .map((s, i) => `Step ${i + 1}: ${s.step || ""} | Document: ${s.document || ""} | Folder: ${s.folder || ""}`)
    .join(" || ");
} else {
  out.steps_summary = "";
}

// --- PRIORITY NUMBER ---
const p = out.priority.toUpperCase();
if (p === "H") out.priority_number = 3;
else if (p === "M") out.priority_number = 2;
else if (p === "L") out.priority_number = 1;
else out.priority_number = 0;

// ===============================
// RETURN SINGLE ITEM
// ===============================
return [{ json: out }];

